const BATCH_LIMIT = 10;

function clean(value) {
  if (value === undefined || value === null) return '';
  return String(value).trim();
}

function status(value) {
  return clean(value).toLowerCase();
}

function buildSearchQuery(row) {
  const blk = clean(row['Blk']);
  const streetName = clean(row['Street Name']);
  const projectName = clean(row['Project Name']);

  if (blk && streetName) return `${blk} ${streetName}`.replace(/\s+/g, ' ').trim();
  if (projectName && streetName) return `${projectName} ${streetName}`.replace(/\s+/g, ' ').trim();
  if (projectName) return projectName.replace(/\s+/g, ' ').trim();
  return streetName.replace(/\s+/g, ' ').trim();
}

const output = [];

for (const item of items) {
  const row = item.json;
  const automationEligible = clean(row['Automation Eligible']).toLowerCase();
  const oneMapStatus = status(row['OneMap Status']);

  if (automationEligible !== 'yes') continue;
  if (oneMapStatus && oneMapStatus !== 'pending' && oneMapStatus !== 'error') continue;

  const query = buildSearchQuery(row);
  if (!query) continue;

  output.push({
    json: {
      ...row,
      'OneMap Search Query': query,
      'OneMap Status': 'Pending',
      'OneMap Notes': 'Selected for Module 2B OneMap enrichment batch run',
    },
  });

  if (output.length >= BATCH_LIMIT) break;
}

return output;

function clean(value) {
  if (value === undefined || value === null) return '';
  return String(value).trim();
}

function singaporeTimestamp() {
  const now = new Date();
  const singaporeTime = new Date(now.toLocaleString('en-US', { timeZone: 'Asia/Singapore' }));
  const yyyy = singaporeTime.getFullYear();
  const mm = String(singaporeTime.getMonth() + 1).padStart(2, '0');
  const dd = String(singaporeTime.getDate()).padStart(2, '0');
  const hh = String(singaporeTime.getHours()).padStart(2, '0');
  const min = String(singaporeTime.getMinutes()).padStart(2, '0');
  return `${yyyy}-${mm}-${dd} ${hh}:${min}`;
}

function normalise(value) {
  return clean(value).toUpperCase().replace(/[^A-Z0-9 ]/g, ' ').replace(/\s+/g, ' ').trim();
}

function tokenSet(value) {
  return new Set(normalise(value).split(' ').filter(Boolean));
}

function confidenceFor(query, result) {
  const queryTokens = tokenSet(query);
  const resultTokens = tokenSet(`${result.ADDRESS || ''} ${result.SEARCHVAL || ''}`);
  if (!queryTokens.size || !resultTokens.size) return '';

  let overlap = 0;
  for (const token of queryTokens) {
    if (resultTokens.has(token)) overlap += 1;
  }

  const ratio = overlap / queryTokens.size;
  if (ratio >= 0.9) return 'High';
  if (ratio >= 0.6) return 'Medium';
  return 'Low';
}

function oneMapStatusFromConfidence(confidence, resultCount) {
  if (!resultCount) return 'No Match';
  if (confidence === 'High') return 'Matched';
  return 'Needs Review';
}

