const selectedRows = $('Select Eligible Registry Rows - Batch 10').all();
const now = singaporeTimestamp();
const output = [];

for (let i = 0; i < items.length; i++) {
  const selectedRow = selectedRows[i]?.json || {};
  const response = items[i]?.json || {};

  const baseUpdate = {
    'Source Key': selectedRow['Source Key'],
    'Property Record ID': selectedRow['Property Record ID'],
    'OneMap Search Query': selectedRow['OneMap Search Query'],
    'OneMap Last Updated': now,
  };

  if (!baseUpdate['Source Key']) continue;

  if (response.error || response.statusCode >= 400) {
    output.push({
      json: {
        ...baseUpdate,
        'OneMap Status': 'Error',
        'OneMap Notes': `OneMap API error: ${clean(response.error || response.message || response.statusCode)}`,
      },
    });
    continue;
  }

  const results = Array.isArray(response.results) ? response.results : [];
  const best = results[0] || null;

  if (!best) {
    output.push({
      json: {
        ...baseUpdate,
        'OneMap Status': 'No Match',
        'OneMap Notes': 'No OneMap search results returned for query',
      },
    });
    continue;
  }

  const postal = clean(best.POSTAL).padStart(6, '0');
  const district = districtFromPostal(postal);
  const confidence = confidenceFor(selectedRow['OneMap Search Query'], best);
  const matchStatus = oneMapStatusFromConfidence(confidence, results.length);

  output.push({
    json: {
      ...baseUpdate,
      'Postal Code': postal,
      'OneMap Matched Address': clean(best.ADDRESS || best.SEARCHVAL),
      'OneMap Building': clean(best.BUILDING) === 'NIL' ? '' : clean(best.BUILDING),
      'OneMap Latitude': clean(best.LATITUDE),
      'OneMap Longitude': clean(best.LONGITUDE || best.LONGTITUDE),
      'Address Match Confidence': confidence,
      'OneMap Status': matchStatus,
      'OneMap Last Updated': now,
      'OneMap Notes': `Matched first OneMap result from ${results.length} returned result(s)`,
      'District': district,
      'URA Batch': '',
    },
  });
}

return output;
